)

const supportedValeVersion = "vale version 3.13.0"

// DiagnosticIssue represents a detected problem and its remediation
type DiagnosticIssue struct {
	Type        string
	Description string
	Remediation []string
	SystemInfo  map[string]string
}

// runDoctor implements the doctor command logic
func (f *CommandFactory) runDoctor(cmd *cobra.Command, args []string) error {
	pathsStr, _ := cmd.Flags().GetString("paths")
	if pathsStr != "" {
		return f.runDoctorScoped(strings.Fields(pathsStr))
	}

	verbose, _ := cmd.Flags().GetBool("verbose")
	applyHousekeeping, _ := cmd.Flags().GetBool("apply")
	fix, _ := cmd.Flags().GetBool("fix")

	fmt.Println("🩺 DDx Installation Diagnostics")
	fmt.Println("=====================================")
	fmt.Println()

	var issues []DiagnosticIssue
	allGood := true
	auditPlugins, _ := cmd.Flags().GetBool("plugins")

	// Check 1: DDX Binary Executable and Install Location
	fmt.Print("✓ Checking DDX Binary... ")
	executable, err := os.Executable()
	if err != nil {
		fmt.Println("❌ Cannot determine executable location")
		allGood = false
	} else {
		fmt.Printf("✅ DDX Binary Executable (%s)\n", executable)
		if locationIssues := checkBinaryInstallLocation(executable); len(locationIssues) > 0 {
			for _, issue := range locationIssues {
				fmt.Printf("   ⚠️  %s\n", issue.Description)
				for _, r := range issue.Remediation {
					fmt.Printf("   💡 %s\n", r)
				}
			}
			issues = append(issues, locationIssues...)
		}
	}

	// Check 2: PATH Configuration
	fmt.Print("✓ Checking PATH Configuration... ")
	if isInPath() {
		fmt.Println("✅ PATH Configuration")
	} else {
		fmt.Println("⚠️  DDX not found in PATH")

		// Check for problem simulation
		problemState := os.Getenv("DDX_PROBLEM_STATE")
		if problemState == "path_issue" || verbose {
			issues = append(issues, DiagnosticIssue{
				Type:        "path_configuration",
				Description: "DDX binary not accessible from PATH",
				Remediation: []string{
					"Run 'ddx setup path'",
					"Restart shell session",
					"Manually add to PATH",
				},
				SystemInfo: map[string]string{
					"shell": os.Getenv("SHELL"),
					"path":  os.Getenv("PATH"),
				},
			})
		}

		if !verbose {
			suggestPathFix()
		}
		// Not marking as failure since DDx is running
	}

	// Check 3: Configuration File
	fmt.Print("✓ Checking Configuration... ")
	if checkConfiguration() {
		fmt.Println("✅ Configuration Valid")
	} else {
		fmt.Println("⚠️  Configuration Issues (non-critical)")
	}

	// Check 3b: Legacy DDx-side model catalog file.
	fmt.Print("✓ Checking Legacy Model Catalog... ")
	if legacyCatalog := checkLegacyModelCatalogFile(); legacyCatalog != nil {
		fmt.Println("⚠️  Legacy DDx-side model catalog found")
		for _, r := range legacyCatalog.Remediation {
			fmt.Printf("   💡 %s\n", r)
		}
		issues = append(issues, *legacyCatalog)
	} else {
		fmt.Println("✅ No legacy DDx-side model catalog file")
	}

	// Check 3c: Pinned Vale prose checker.
	fmt.Print("✓ Checking Prose Checker... ")
	proseCheck := checkProseChecker()
	if proseCheck.Issue == nil {
		fmt.Println("✅ Vale prose checker")
	} else {
		fmt.Println("⚠️  Vale prose checker unavailable or unsupported")
		fmt.Printf("   ⚠️  %s\n", proseCheck.Issue.Description)
		for _, r := range proseCheck.Issue.Remediation {
			fmt.Printf("   💡 %s\n", r)
		}
		issues = append(issues, *proseCheck.Issue)
	}
	if verbose {
		if proseCheck.Path != "" {
			fmt.Printf("   vale path: %s\n", proseCheck.Path)
		}
		if proseCheck.Version != "" {
			fmt.Printf("   vale version: %s\n", proseCheck.Version)
		}
	}

	// Check 4: Git Installation
	fmt.Print("✓ Checking Git... ")
	if checkGit() {
		fmt.Println("✅ Git Available")
	} else {
		fmt.Println("❌ Git Not Found")
		fmt.Println("   Git is required for DDX synchronization features")
		allGood = false
	}

	// Check 4b: Git Repo Health (core.bare / core.worktree / core.hooksPath corruption)
	fmt.Print("✓ Checking Git Repo Health... ")
	repoIssues := checkGitRepoHealth(f.WorkingDir, fix)
	if len(repoIssues) == 0 {
		fmt.Println("✅ Git Repo Clean")
	} else {
		if fix {
			fmt.Printf("🔧 Git Repo Issues Fixed (%d)\n", len(repoIssues))
		} else {
			fmt.Printf("⚠️  Git Repo Issues (%d) — re-run with --fix to remediate\n", len(repoIssues))
		}
		for _, issue := range repoIssues {
			fmt.Printf("   ⚠️  %s\n", issue.Description)
			for _, r := range issue.Remediation {
				fmt.Printf("   💡 %s\n", r)
			}
		}
		issues = append(issues, repoIssues...)
	}

	// Check 4c: Worktrees master — detect stale execute-bead paths in worktrees.json.
	fmt.Print("✓ Checking Worktrees Registry... ")
	if masterIssue := checkStaleWorktreesMaster(f.WorkingDir); masterIssue != nil {
		fmt.Println("⚠️  Stale worktrees.json master pointer")
		fmt.Printf("   ⚠️  %s\n", masterIssue.Description)
		for _, r := range masterIssue.Remediation {
			fmt.Printf("   💡 %s\n", r)
		}
		issues = append(issues, *masterIssue)
	} else {
		fmt.Println("✅ Worktrees Registry")
	}

	// Check 5: Network Connectivity
	fmt.Print("✓ Checking Network... ")
	if checkNetwork() {
		fmt.Println("✅ Network Connectivity")
	} else {
		fmt.Println("⚠️  Network Issues (optional)")

		// Check for problem simulation
		problemState := os.Getenv("DDX_PROBLEM_STATE")
		if problemState == "network_issue" || verbose {
			issues = append(issues, DiagnosticIssue{
				Type:        "network_connectivity",
				Description: "Unable to reach external repositories",
				Remediation: []string{
					"Check internet connection",
					"Verify proxy settings",
					"Try offline installation",
				},
				SystemInfo: map[string]string{
					"dns_server": "Check /etc/resolv.conf or network settings",
					"proxy":      os.Getenv("HTTP_PROXY"),
				},
			})
		}
	}

	// Check 7: Permissions
	fmt.Print("✓ Checking Permissions... ")
	problemState := os.Getenv("DDX_PROBLEM_STATE")
	if checkPermissions() && problemState != "permission_issue" {
		fmt.Println("✅ File Permissions")
	} else {
		fmt.Println("❌ Permission Issues")
		allGood = false

		// Add permission issue details for critical failures or verbose mode
		if problemState == "permission_issue" || verbose || !checkPermissions() {
			issues = append(issues, DiagnosticIssue{
				Type:        "file_permissions",
				Description: "Cannot create files in current directory",
				Remediation: []string{
					"Check directory permissions",
					"Try installing to different location",
					"Verify user has write access",
				},
				SystemInfo: map[string]string{
					"user":        os.Getenv("USER"),
					"working_dir": f.WorkingDir,
					"permissions": getDirectoryPermissions(f.WorkingDir),
				},
			})
		}
	}

	// Check 8: Library Path
	fmt.Print("✓ Checking Library Path... ")
	if checkLibraryPathFromWorkingDir(f.WorkingDir) {
		fmt.Println("✅ Library Path Accessible")
	} else {
		fmt.Println("⚠️  Library Path Issues (optional)")

		// Check for problem simulation
		problemState := os.Getenv("DDX_PROBLEM_STATE")
		if problemState == "library_path_issue" || verbose {
			issues = append(issues, DiagnosticIssue{
				Type:        "library_path_configuration",
				Description: "DDX library path not accessible or not configured",
				Remediation: []string{
					"Initialize DDX in your project with 'ddx init'",
					"Check .ddx.yml configuration file",
					"Verify library path exists and is readable",
					"Try setting DDX_LIBRARY_BASE_PATH environment variable",

package bead

import (
	"bytes"
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"sort"
	"strings"
	"time"
)

const (
	doctorFindingKindOversizedField       = "oversized_field"
	doctorFindingKindParentAncestorInDeps = "parent_ancestor_in_deps"
	doctorFindingKindDanglingDep          = "dangling_dep"
	doctorFindingKindUnparseableLine      = "unparseable_line"
)

// DoctorFinding reports a single bead doctor issue. Findings cover oversized
// field values, dependency edges that point back into the bead's parent chain,
// and line-level parse failures.
type DoctorFinding struct {
	Kind         string   `json:"kind,omitempty"`
	BeadID       string   `json:"bead_id"`
	FieldPath    string   `json:"field_path"`
	TargetID     string   `json:"target_id,omitempty"`
	DependencyID string   `json:"dependency_id,omitempty"`
	AncestorID   string   `json:"ancestor_id,omitempty"`
	ParentChain  []string `json:"parent_chain,omitempty"`
	SizeBytes    int      `json:"size_bytes,omitempty"`
	SampleHead   string   `json:"sample_head,omitempty"`
}

// DoctorReport is the output of BeadDoctor — an ordered list of findings.
type DoctorReport struct {
	Path     string
	Findings []DoctorFinding
}

// Clean is true when there are no findings.
func (r DoctorReport) Clean() bool { return len(r.Findings) == 0 }

type doctorRow struct {
	lineNo   int
	rawLine  []byte
	raw      map[string]any
	bead     *Bead
	parseErr error
}

func loadDoctorRows(path string) ([]doctorRow, error) {
	src, err := os.ReadFile(path)
	if err != nil {
		return nil, err
	}

	lines := bytes.Split(src, []byte{'\n'})
	rows := make([]doctorRow, 0, len(lines))
	for i, line := range lines {
		trimmed := bytes.TrimSpace(line)
		if len(trimmed) == 0 {
			continue
		}
		row := doctorRow{
			lineNo:  i + 1,
			rawLine: append([]byte(nil), line...),
		}
		if err := json.Unmarshal(trimmed, &row.raw); err != nil {
			row.parseErr = err
			rows = append(rows, row)
			continue
		}
		bead, err := unmarshalBead(trimmed)
		if err != nil {
			row.parseErr = err
			rows = append(rows, row)
			continue
		}
		row.bead = &bead
		rows = append(rows, row)
	}
	return rows, nil
}

// BeadDoctor scans a beads.jsonl file and returns every oversized field and
// every dependency edge that points back into the bead's parent chain.
// Lines that fail to parse are reported as a single finding with
// Kind=unparseable_line and the raw line as the sample.
func BeadDoctor(path string) (DoctorReport, error) {
	report := DoctorReport{Path: path}
	rows, err := loadDoctorRows(path)
	if err != nil {
		return report, err
	}

	byID := make(map[string]*Bead, len(rows))
	for _, row := range rows {
		if row.bead == nil || row.bead.ID == "" {
			continue
		}
		byID[row.bead.ID] = row.bead
	}

	// knownIDs is the set of all bead IDs that a dependency may legitimately
	// reference: the active file plus the archive sibling (closed beads migrate
	// there but stay valid dependency targets). A dependency whose target is in
	// neither is dangling — it can never be satisfied, so it blocks readiness
	// forever. Archive presence is best-effort; an absent archive just means
	// every target is checked against the active file.
	knownIDs := make(map[string]struct{}, len(byID))
	for id := range byID {
		knownIDs[id] = struct{}{}
	}
	for id := range loadArchiveBeadIDs(path) {
		knownIDs[id] = struct{}{}
	}

	for _, row := range rows {
		if row.parseErr != nil {
			report.Findings = append(report.Findings, DoctorFinding{
				Kind:       doctorFindingKindUnparseableLine,
				BeadID:     fmt.Sprintf("line %d (unparseable)", row.lineNo),
				FieldPath:  "line",
				SizeBytes:  len(bytes.TrimSpace(row.rawLine)),
				SampleHead: firstN(string(bytes.TrimSpace(row.rawLine)), 80),
			})
			continue
		}
		if row.bead == nil {
			continue
		}
		report.Findings = append(report.Findings, oversizedFieldFindings(row.bead)...)
		report.Findings = append(report.Findings, parentAncestorDepFindings(row.bead, byID)...)
		report.Findings = append(report.Findings, danglingDepFindings(row.bead, knownIDs)...)
	}

	sortDoctorFindings(report.Findings)
	return report, nil
}

func oversizedFieldFindings(b *Bead) []DoctorFinding {
	findings := make([]DoctorFinding, 0, 5)
	if b == nil {
		return findings
	}
	for _, field := range []string{"description", "acceptance", "notes"} {
		if s := beadFieldString(b, field); len(s) > MaxFieldBytes {
			findings = append(findings, DoctorFinding{
				Kind:       doctorFindingKindOversizedField,
				BeadID:     b.ID,
				FieldPath:  field,
				SizeBytes:  len(s),
				SampleHead: firstN(s, 80),
			})
		}
	}
	for i, ev := range decodeBeadEvents(b.Extra["events"]) {
		for _, field := range []string{"body", "summary"} {
			if s := beadEventString(ev, field); len(s) > MaxFieldBytes {
				findings = append(findings, DoctorFinding{
					Kind:       doctorFindingKindOversizedField,
					BeadID:     b.ID,
					FieldPath:  fmt.Sprintf("events[%d].%s", i, field),
					SizeBytes:  len(s),
					SampleHead: firstN(s, 80),
				})
			}
		}
	}
	return findings
}

func beadFieldString(b *Bead, field string) string {
	switch field {
	case "description":
		return b.Description
	case "acceptance":
		return b.Acceptance
	case "notes":
		return b.Notes
	default:
		return ""
	}
}

func beadEventString(ev BeadEvent, field string) string {
	switch field {
	case "body":
		return ev.Body
	case "summary":
		return ev.Summary
	default:
		return ""
	}
}

func parentAncestorDepFindings(b *Bead, byID map[string]*Bead) []DoctorFinding {
	if b == nil {
		return nil
	}
	chain, _ := beadParentChain(byID, b.Parent)
	if len(chain) == 0 || len(b.Dependencies) == 0 {
		return nil
	}
	ancestorSet := make(map[string]struct{}, len(chain))
	for _, ancestorID := range chain {
		ancestorSet[ancestorID] = struct{}{}
	}

	findings := make([]DoctorFinding, 0, len(b.Dependencies))
	for i, dep := range b.Dependencies {
		if _, ok := ancestorSet[dep.DependsOnID]; !ok {
			continue
		}
		findings = append(findings, DoctorFinding{
			Kind:         doctorFindingKindParentAncestorInDeps,
			BeadID:       b.ID,
			FieldPath:    fmt.Sprintf("dependencies[%d].depends_on_id", i),
			TargetID:     dep.DependsOnID,
			DependencyID: dep.DependsOnID,
			AncestorID:   dep.DependsOnID,
			ParentChain:  append([]string(nil), chain...),
			SampleHead:   strings.Join(chain, " -> "),
		})
	}
	return findings
}

// danglingDepFindings flags dependency edges whose target bead exists in
// neither the active file nor the archive. Such an edge can never be satisfied
// (its target will never reach status=closed because it does not exist), so the
// referring bead is blocked from readiness permanently. These accumulate when a
// tracker merge unions in dependency edges from a branch/worktree whose child
// bead records were dropped, or when a malformed/worktree-prefixed child ID is
// written. Mutually exclusive with parent_ancestor_in_deps: an ancestor target
// must exist to be in the parent chain, a dangling target does not exist.
func danglingDepFindings(b *Bead, knownIDs map[string]struct{}) []DoctorFinding {
	if b == nil || len(b.Dependencies) == 0 {
		return nil
	}
	findings := make([]DoctorFinding, 0, len(b.Dependencies))
	for i, dep := range b.Dependencies {
		target := strings.TrimSpace(dep.DependsOnID)
		if target == "" {
			continue
		}
		if _, ok := knownIDs[target]; ok {
			continue
		}
		findings = append(findings, DoctorFinding{
			Kind:         doctorFindingKindDanglingDep,
			BeadID:       b.ID,
			FieldPath:    fmt.Sprintf("dependencies[%d].depends_on_id", i),
			TargetID:     target,
			DependencyID: target,
		})
	}
	return findings

