			continue
		}
		stale, _ := staleWorkerDir(rec, now, r.workerDirMaxAge)
		if !stale {
			continue
		}

		report.StaleWorkerDirs++
		if !apply {
			continue
		}

		dirPath := filepath.Join(root, entry.Name())
		if err := os.RemoveAll(dirPath); err != nil {
			report.Warnings = append(report.Warnings, agent.ExecutionCleanupWarning{
				Path:    dirPath,
				Class:   "worker_dir_remove",
				Message: err.Error(),
			})
			continue
		}
		report.RemovedWorkerDirs++
	}

	return nil
}

func (r *startupHousekeepingRunner) scanExecutionDirs(ctx context.Context, now time.Time, runStates []agent.RunState, apply bool, report *startupHousekeepingReport) error {
	policy := r.retentionPolicy
	if policy.mode == executionRetentionDisabled {
		return nil
	}

	root := ddxroot.JoinProject(r.projectRoot, "executions")
	entries, err := os.ReadDir(root)
	if err != nil {
		if os.IsNotExist(err) {
			return nil
		}
		return err
	}

	activeAttempts := map[string]struct{}{}
	for _, rs := range runStates {
		if rs.AttemptID != "" {
			activeAttempts[rs.AttemptID] = struct{}{}
		}
	}
	cutoff := now.AddDate(0, 0, -policy.days)

	for _, entry := range entries {
		if !entry.IsDir() {
			continue
		}
		if _, ok := activeAttempts[entry.Name()]; ok {
			continue
		}
		if ctx != nil {
			if err := ctx.Err(); err != nil {
				return err
			}
		}

		dirPath := filepath.Join(root, entry.Name())
		if !hasExecutionEvidenceMarker(dirPath) {
			continue
		}

		info, err := entry.Info()
		if err != nil {
			report.Warnings = append(report.Warnings, agent.ExecutionCleanupWarning{
				Path:    dirPath,
				Class:   "execution_dir_stat",
				Message: err.Error(),
			})
			continue
		}
		if !info.ModTime().Before(cutoff) {
			continue
		}

		report.StaleExecutionDirs++
		if !apply {
			continue
		}

		switch policy.mode {
		case executionRetentionArchive:
			if err := archiveExecutionDir(r.projectRoot, dirPath, entry.Name(), info.ModTime()); err != nil {
				report.Warnings = append(report.Warnings, agent.ExecutionCleanupWarning{
					Path:    dirPath,
					Class:   "execution_dir_archive",
					Message: err.Error(),
				})
				continue
			}
			report.ArchivedExecutionDirs++
		case executionRetentionDelete:
			if err := os.RemoveAll(dirPath); err != nil {
				report.Warnings = append(report.Warnings, agent.ExecutionCleanupWarning{
					Path:    dirPath,
					Class:   "execution_dir_remove",
					Message: err.Error(),
				})
				continue
			}
			report.DeletedExecutionDirs++
		}
	}

	return nil
}

func staleWorkerDir(rec workerstatus.LivenessRecord, now time.Time, maxAge time.Duration) (bool, string) {
	if rec.PID > 0 && !processAlive(rec.PID) {
		return true, fmt.Sprintf("worker pid %d is no longer live", rec.PID)
	}
	if !rec.LastActivityAt.IsZero() && now.Sub(rec.LastActivityAt) > maxAge {
		return true, fmt.Sprintf("last activity older than %s", maxAge)
	}
	return false, ""
}

func resolveExecutionRetentionPolicy(projectRoot string) executionRetentionPolicy {
	if raw := strings.TrimSpace(os.Getenv(executionRetentionOverrideEnv)); raw != "" {
		if days, err := strconv.Atoi(raw); err == nil && days >= 0 {
			if days == 0 {
				return executionRetentionPolicy{days: 0, mode: executionRetentionDelete}
			}
			return executionRetentionPolicy{days: days, mode: executionRetentionArchive}
		}
	}

	cfgPath := ddxroot.JoinProject(projectRoot, "config.yaml")
	cfg, err := config.LoadFromFile(cfgPath)
	if err != nil || cfg == nil || cfg.Executions == nil {
		return executionRetentionPolicy{days: 90, mode: executionRetentionArchive}
	}
	days := cfg.Executions.ResolveRetainDays()
	if days == 0 {
		return executionRetentionPolicy{days: 0, mode: executionRetentionDisabled}
	}
	return executionRetentionPolicy{days: days, mode: executionRetentionArchive}
}

func hasExecutionEvidenceMarker(dirPath string) bool {
	for _, name := range []string{"result.json", "manifest.json"} {
		if _, err := os.Stat(filepath.Join(dirPath, name)); err == nil {
			return true
		}
	}
	return false
}

func archiveExecutionDir(projectRoot, dirPath, attemptID string, modTime time.Time) error {
	year, month := executionArchiveBucket(attemptID, modTime.UTC())
	dstRoot := filepath.Join(projectRoot, filepath.FromSlash(executionRetentionArchiveRoot), year, month)
	if err := os.MkdirAll(dstRoot, 0o755); err != nil {
		return fmt.Errorf("mkdir archive dir: %w", err)
	}
	dstPath := filepath.Join(dstRoot, attemptID)
	if _, err := os.Stat(dstPath); err == nil {
		return fmt.Errorf("archive destination already exists: %s", dstPath)
	} else if !errors.Is(err, os.ErrNotExist) {
		return err
	}
	return os.Rename(dirPath, dstPath)
}

func executionArchiveBucket(attemptID string, modTime time.Time) (string, string) {
	ts := attemptID
	if idx := strings.IndexByte(ts, '-'); idx >= 0 {
		ts = ts[:idx]
	}
	if parsed, err := time.ParseInLocation(executionRetentionTimestampLayout, ts, time.UTC); err == nil {
		return parsed.Format("2006"), parsed.Format("01")
	}
	if modTime.IsZero() {
		modTime = time.Now().UTC()
	}
	return modTime.Format("2006"), modTime.Format("01")
}

package cmd

import (
	"context"
	"errors"
	"fmt"
	"os"
	"path/filepath"
	"strconv"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
	"github.com/DocumentDrivenDX/ddx/internal/config"
	"github.com/DocumentDrivenDX/ddx/internal/ddxroot"
	"github.com/DocumentDrivenDX/ddx/internal/workerstatus"
)

const (
	defaultWorkerDirStaleAge          = 30 * time.Minute
	executionRetentionArchiveRoot     = ".ddx/executions-archive"
	executionRetentionOverrideEnv     = "DDX_EXECUTION_RETAIN_DAYS"
	executionRetentionTimestampLayout = "20060102T150405"
)

type executionRetentionMode int

const (
	executionRetentionDisabled executionRetentionMode = iota
	executionRetentionArchive
	executionRetentionDelete
)

type executionRetentionPolicy struct {
	days int
	mode executionRetentionMode
}

type startupHousekeepingReport struct {
	ProjectRoot string
	TempRoot    string
	runStates   []agent.RunState
	registered  map[string]struct{}

	StaleWorktrees     int64
	StaleWorkerDirs    int64
	StaleExecutionDirs int64

	RemovedRegisteredWorktrees  int64
	RemovedUnregisteredTempDirs int64
	RemovedWorkerDirs           int64
	ArchivedExecutionDirs       int64
	DeletedExecutionDirs        int64

	Warnings []agent.ExecutionCleanupWarning
}

type startupHousekeepingRunner struct {
	projectRoot     string
	tempRoot        string
	worktreeMaxAge  time.Duration
	workerDirMaxAge time.Duration
	now             func() time.Time
	retentionPolicy executionRetentionPolicy
	processCleanup  startupProcessCleanupFunc
}

func newStartupHousekeepingRunner(projectRoot string) *startupHousekeepingRunner {
	return &startupHousekeepingRunner{
		projectRoot:     projectRoot,
		tempRoot:        config.ExecutionTempRoot(projectRoot),
		worktreeMaxAge:  worktreeReapMaxAgeFromEnv(),
		workerDirMaxAge: defaultWorkerDirStaleAge,
		retentionPolicy: resolveExecutionRetentionPolicy(projectRoot),
		processCleanup:  defaultStartupProcessCleanup,
	}
}

func (r *startupHousekeepingRunner) Cleanup(ctx context.Context) (agent.ExecutionCleanupSummary, error) {
	if r == nil {
		return agent.ExecutionCleanupSummary{}, nil
	}
	report, err := r.scan(ctx, true)
	if err != nil {
		return agent.ExecutionCleanupSummary{
			ProjectRoot: r.projectRoot,
			TempRoot:    r.tempRoot,
		}, err
	}
	summary := agent.ExecutionCleanupSummary{
		ProjectRoot:                 report.ProjectRoot,
		TempRoot:                    report.TempRoot,
		RemovedRegisteredWorktrees:  report.RemovedRegisteredWorktrees,
		RemovedUnregisteredTempDirs: report.RemovedUnregisteredTempDirs,
		RemovedWorkerDirs:           report.RemovedWorkerDirs,
		RemovedEvidenceDirs:         report.ArchivedExecutionDirs + report.DeletedExecutionDirs,
		Warnings:                    append([]agent.ExecutionCleanupWarning(nil), report.Warnings...),
	}
	if r.processCleanup != nil {
		now := time.Now().UTC()
		if r.now != nil {
			now = r.now()
		}
		if procErr := r.processCleanup(ctx, report.ProjectRoot, report.TempRoot, &summary, report.runStates, report.registered, now); procErr != nil {
			return summary, procErr
		}
	}
	return summary, nil
}

func (r *startupHousekeepingRunner) scan(ctx context.Context, apply bool) (startupHousekeepingReport, error) {
	if r == nil {
		return startupHousekeepingReport{}, nil
	}
	report := startupHousekeepingReport{
		ProjectRoot: r.projectRoot,
		TempRoot:    r.tempRoot,
	}
	if r.projectRoot == "" {
		return report, nil
	}
	now := time.Now().UTC()
	if r.now != nil {
		now = r.now()
	}

	runStates, err := agent.ReadRunStates(r.projectRoot)
	if err != nil {
		return report, err
	}
	report.runStates = append([]agent.RunState(nil), runStates...)
	if err := r.scanWorktrees(ctx, now, runStates, apply, &report); err != nil {
		return report, err
	}
	if err := r.scanWorkerDirs(ctx, now, apply, &report); err != nil {
		return report, err
	}
	if err := r.scanExecutionDirs(ctx, now, runStates, apply, &report); err != nil {
		return report, err
	}
	return report, nil
}

func (r *startupHousekeepingRunner) scanWorktrees(ctx context.Context, now time.Time, runStates []agent.RunState, apply bool, report *startupHousekeepingReport) error {
	if report.TempRoot == "" {
		return nil
	}
	if ctx != nil {
		if err := ctx.Err(); err != nil {
			return err
		}
	}
	entries, err := os.ReadDir(report.TempRoot)
	if err != nil {
		if os.IsNotExist(err) {
			return nil
		}
		return err
	}

	registered := map[string]struct{}{}
	if paths, listErr := (&agent.RealGitOps{}).WorktreeList(r.projectRoot); listErr == nil {
		for _, path := range paths {
			registered[filepath.Clean(path)] = struct{}{}
		}
	}
	report.registered = registered

	for _, entry := range entries {
		if !entry.IsDir() || !strings.HasPrefix(entry.Name(), agent.ExecuteBeadWtPrefix) {
			continue
		}
		if ctx != nil {
			if err := ctx.Err(); err != nil {
				return err
			}
		}
		info, err := entry.Info()
		if err != nil {
			report.Warnings = append(report.Warnings, agent.ExecutionCleanupWarning{
				Path:    filepath.Join(report.TempRoot, entry.Name()),
				Class:   "worktree_stat",
				Message: err.Error(),
			})
			continue
		}
		if now.Sub(info.ModTime()) < r.worktreeMaxAge {
			continue
		}

		path := filepath.Join(report.TempRoot, entry.Name())
		meta, metaErr := agent.ReadExecutionCleanupMetadata(path)
		if metaErr == nil {
			meta.WorktreePath = firstNonEmpty(meta.WorktreePath, path)
		} else {
			meta = agent.ExecutionCleanupMetadata{WorktreePath: path}
		}
		if worktreeStillLive(meta, runStates, now) {
			continue
		}

		report.StaleWorktrees++
		if !apply {
			continue
		}

		if _, ok := registered[filepath.Clean(path)]; ok {
			if err := (&agent.RealGitOps{}).WorktreeRemove(r.projectRoot, path); err != nil {
				report.Warnings = append(report.Warnings, agent.ExecutionCleanupWarning{
					Path:    path,
					Class:   "registered_worktree_remove",
					Message: err.Error(),
				})
				continue
			}
			report.RemovedRegisteredWorktrees++
			continue
		}

		if err := os.RemoveAll(path); err != nil {
			report.Warnings = append(report.Warnings, agent.ExecutionCleanupWarning{
				Path:    path,
				Class:   "unregistered_worktree_remove",
				Message: err.Error(),
			})
			continue
		}
		report.RemovedUnregisteredTempDirs++
	}

	return nil
}

func (r *startupHousekeepingRunner) scanWorkerDirs(ctx context.Context, now time.Time, apply bool, report *startupHousekeepingReport) error {
	root := workerstatus.LivenessDir(r.projectRoot)
	entries, err := os.ReadDir(root)
	if err != nil {
		if os.IsNotExist(err) {
			return nil
		}
		return err
	}

	for _, entry := range entries {
		if !entry.IsDir() || !strings.HasPrefix(entry.Name(), "agent-loop-") {
			continue
		}
		if ctx != nil {
			if err := ctx.Err(); err != nil {
				return err
			}
		}

		rec, err := workerstatus.ReadLiveness(r.projectRoot, entry.Name())
		if err != nil {
			report.Warnings = append(report.Warnings, agent.ExecutionCleanupWarning{
				Path:    filepath.Join(root, entry.Name(), "status.json"),
				Class:   "worker_dir_read",
				Message: err.Error(),
			})

package agent

import (
	"fmt"
	"os"
	"path/filepath"
	"strconv"
	"strings"
	"sync"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/lockmetrics"
)

// LockRetryPolicy describes the retry/backoff curve used when attempting to
// acquire a process-shared lock that guards git index operations on the
// primary .git (the tracker-commit lock). The policy is owned by this
// package per ddx-da11a34a AC#4: callers in cli/internal/triage and
// elsewhere consult ActionRetryWithBackoff but do not duplicate the curve
// implementation here.
//
// The curve is exponential with a cap and a bounded max-retries budget so
// that lock contention is absorbed silently up to a point, after which it
// surfaces as an ordinary error to the caller. Per TD-031 §8.5
// (LockContentionContract) lock contention does NOT change persisted bead
// status; the bead remains claimable and the worker remains `draining`.
type LockRetryPolicy struct {
	// InitialBackoff is the wait before the second attempt.
	InitialBackoff time.Duration
	// MaxBackoff caps the per-step backoff after exponential growth.
	MaxBackoff time.Duration
	// Multiplier is the per-step growth factor (>= 1.0).
	Multiplier float64
	// MaxRetries bounds the number of acquisition attempts after the
	// initial try. Total attempts = MaxRetries + 1.
	MaxRetries int
	// MaxElapsed bounds the total wall-clock time spent retrying. If both
	// MaxRetries and MaxElapsed are set, the first to trip wins.
	MaxElapsed time.Duration
}

// DefaultLockRetryPolicy returns the policy used by withTrackerLock. The
// curve is intentionally tight (sub-second) for in-process tracker-commit
// contention; the larger 30s/90s/300s curve referenced by the auto-triage
// child of ddx-3c154349 lives one layer up, in cli/internal/triage —
// it consults ActionRetryWithBackoff and re-queues across drain passes,
// while this policy resolves contention within a single attempt.
func DefaultLockRetryPolicy() LockRetryPolicy {
	return LockRetryPolicy{
		InitialBackoff: 50 * time.Millisecond,
		MaxBackoff:     1 * time.Second,
		Multiplier:     2.0,
		MaxRetries:     200,
		MaxElapsed:     30 * time.Second,
	}
}

// step returns the backoff duration for retry index n (0-based: n=0 is the
// wait BEFORE the second acquisition attempt).
func (p LockRetryPolicy) step(n int) time.Duration {
	if p.InitialBackoff <= 0 {
		return 0
	}
	d := float64(p.InitialBackoff)
	m := p.Multiplier
	if m < 1 {
		m = 1
	}
	for i := 0; i < n; i++ {
		d *= m
		if p.MaxBackoff > 0 && d >= float64(p.MaxBackoff) {
			d = float64(p.MaxBackoff)
			break
		}
	}
	out := time.Duration(d)
	if p.MaxBackoff > 0 && out > p.MaxBackoff {
		out = p.MaxBackoff
	}
	return out
}

// trackerLockStaleAge is the age after which a held tracker lock is
// considered stale (owner crashed mid-commit) and may be forcibly broken.
var trackerLockStaleAge = 10 * time.Minute

// trackerLockPolicy is the active retry policy for withTrackerLock.
// Tests may swap this out via the exported helpers below.
var trackerLockPolicy = DefaultLockRetryPolicy()

// trackerLockPath returns the main-git lock directory for the given project
// root. The historical name remains because tests and older comments refer to
// the tracker lock, but the lock now protects all primary-checkout git writes:
// tracker commits, pre-dispatch checkpoint/ref updates, and landing.
//
// The lock target must be shared across linked worktrees for the same repo, so
// we prefer the primary DDx workspace when one exists instead of the caller's
// checkout-local .ddx directory.
func trackerLockPath(projectRoot string) string {
	return lockmetrics.SharedTrackerLockPath(projectRoot)
}

// withMainGitLock acquires the process-shared main-git lock for the
// given project root, runs fn, and releases the lock. The lock is a
// directory created via os.Mkdir (atomic across processes on POSIX and
// Windows) following the same pattern as cli/internal/bead/lock.go.
//
// section identifies the call site (e.g. "durable_audit", "pre_dispatch",
// "land") and is surfaced in TrackerLockSample.Section and in the lockmetrics
// operation label so slow holds can be attributed without reading source.
//
// Contention is handled per LockRetryPolicy: exponential backoff up to a
// bounded budget. Per TD-031 §8.5 the contention itself does not change
// bead status; on budget exhaustion the caller surfaces an ordinary
// execution_failed and triage decides next steps.
func withMainGitLock(projectRoot, section string, fn func() error) error {
	if projectRoot == "" {
		return fn()
	}
	return withTrackerLockPolicy(projectRoot, section, trackerLockPolicy, fn)
}

// WithMainGitLock exposes the process-shared main-git lock to sibling
// packages that need the same serialized add/commit boundary as execute-bead
// landing and pre-dispatch checkpointing.
func WithMainGitLock(projectRoot, section string, fn func() error) error {
	return withMainGitLock(projectRoot, section, fn)
}

// withTrackerLock is retained for existing tracker/pre-dispatch call sites. It
// uses the same process-shared lock as landing so separate ddx work processes
// cannot interleave commits, ref updates, and checkout sync in the main tree.
func withTrackerLock(projectRoot, section string, fn func() error) error {
	return withMainGitLock(projectRoot, section, fn)
}

// TrackerLockSample carries timing and contention metrics for one
// withTrackerLock / withMainGitLock acquire+release cycle.
type TrackerLockSample struct {
	LockDir string
	Section string        // call-site identifier, e.g. "durable_audit", "pre_dispatch", "land"
	Wait    time.Duration // time from entry to lock acquisition
	Hold    time.Duration // time the callback held the lock
	Retries int           // number of sleep-and-retry iterations (0 = acquired on first try)
}

var (
	trackerLockSinkMu sync.RWMutex
	trackerLockSinkFn func(TrackerLockSample)
)

// TrackerLockTimeoutError marks a tracker-lock acquisition timeout so callers
// can classify it with errors.Is even when the error is wrapped several times.
type TrackerLockTimeoutError struct {
	Why      string
	LockDir  string
	OwnerPID string
}

// TrackerLockTimeoutErr is the sentinel used by errors.Is for transient
// tracker-lock contention.
var TrackerLockTimeoutErr = &TrackerLockTimeoutError{}

func (e *TrackerLockTimeoutError) Error() string {
	if e == nil {
		return "tracker lock timeout"
	}
	why := strings.TrimSpace(e.Why)
	if why == "" {
		why = "unknown"
	}
	lockDir := strings.TrimSpace(e.LockDir)
	if lockDir == "" {
		lockDir = "unknown"
	}
	owner := strings.TrimSpace(e.OwnerPID)
	if owner == "" {
		owner = "missing"
	}
	return fmt.Sprintf("tracker lock timeout (%s, lock: %s, owner pid: %s)", why, lockDir, owner)
}

func (e *TrackerLockTimeoutError) Is(target error) bool {
	_, ok := target.(*TrackerLockTimeoutError)
	return ok
}

// SetTrackerLockMetricsSink atomically installs a new tracker-lock
// metrics sink and returns the previous one. Passing nil disables
// emission. Safe for concurrent use; two workers in the same process
// will not race on the sink variable.
func SetTrackerLockMetricsSink(fn func(TrackerLockSample)) func(TrackerLockSample) {
	trackerLockSinkMu.Lock()
	prev := trackerLockSinkFn
	trackerLockSinkFn = fn
	trackerLockSinkMu.Unlock()
	return prev
}

// trackerLockContendedAttemptHook is a test-only hook fired after each
// failed acquire attempt that has been classified as real lock contention
// (a directory exists at lockDir and the stale-owner path did not reclaim
// it). It is invoked just before the retry sleep with the zero-based
// attempt index. The zero value (nil) is a no-op.
//
// Tests use this hook to deterministically synchronise with the retry
// loop — e.g. release the held lock from the hook so the next attempt
// observes a non-zero retry count without relying on time.Sleep races.
var trackerLockContendedAttemptHook func(attempt int)

// withTrackerLockPolicy is the policy-parameterised form of
// withTrackerLock; exposed at package scope so tests can pin a specific
// curve. section is the call-site identifier forwarded to TrackerLockSample
// and the lockmetrics operation label.
func withTrackerLockPolicy(projectRoot, section string, policy LockRetryPolicy, fn func() error) error {
	lockDir := trackerLockPath(projectRoot)
	if err := os.MkdirAll(filepath.Dir(lockDir), 0o755); err != nil {
		return fmt.Errorf("tracker lock dir: %w", err)
	}

	start := time.Now()
	retries := 0
	for attempt := 0; ; attempt++ {
		err := os.Mkdir(lockDir, 0o755)
		if err == nil {
			_ = os.WriteFile(filepath.Join(lockDir, "pid"),
				[]byte(fmt.Sprintf("%d", os.Getpid())), 0o644)
			_ = os.WriteFile(filepath.Join(lockDir, "acquired_at"),
				[]byte(time.Now().UTC().Format(time.RFC3339)), 0o644)
			break
		}

		// Classify what exists at lockDir before deciding to sleep or fail.
		// Per TD-031 §8.5: only a confirmed lock directory enters retry/backoff;
		// malformed paths are operator diagnostics, not lock contention.
		info, statErr := os.Lstat(lockDir)
		if statErr != nil {
			if os.IsNotExist(statErr) {
				// Path disappeared between Mkdir and Lstat (race). Retry immediately.
				continue

		return nil
	}
	type manifestShape struct {
		Governing []struct {
			ID string `json:"id"`
		} `json:"governing"`
	}
	raw, err := os.ReadFile(manifestAbs)
	if err != nil {
		return nil
	}
	var m manifestShape
	if err := json.Unmarshal(raw, &m); err != nil {
		return nil
	}
	ids := make([]string, 0, len(m.Governing))
	for _, g := range m.Governing {
		if g.ID != "" {
			ids = append(ids, g.ID)
		}
	}
	return ids
}

// RecoverOrphans removes orphaned execute-bead worktrees for a given bead ID.
// This is a belt-and-suspenders sweep for crashed or otherwise unreached
// attempts; the worker now performs the normal post-attempt cleanup on its
// own before the next spawn.
func RecoverOrphans(gitOps GitOps, workDir, beadID string) {
	paths, err := gitOps.WorktreeList(workDir)
	if err != nil {
		return
	}
	// Match by basename prefix so orphans are found regardless of their parent
	// directory (legacy .ddx/ vs new $TMPDIR/ddx-exec-wt/).
	basenamePrefix := ExecuteBeadWtPrefix + beadID + "-"
	orphanRemoved := false
	for _, p := range paths {
		if strings.HasPrefix(filepath.Base(p), basenamePrefix) {
			_ = gitOps.WorktreeRemove(workDir, p)
			orphanRemoved = true
		}
	}
	_ = gitOps.WorktreePrune(workDir)

	// Sweep stale run-state left by crashed workers. Per-attempt records are
	// cleared individually so concurrent attempts for other beads remain visible.
	if states, _ := ReadRunStates(workDir); len(states) > 0 {
		for _, state := range states {
			remove := orphanRemoved && state.BeadID == beadID
			if !remove && state.BeadID == beadID {
				remove = true
			}
			if !remove && state.WorktreePath != "" {
				if _, err := os.Stat(state.WorktreePath); os.IsNotExist(err) {
					remove = true
				}
			}
			if remove {
				_ = ClearRunStateAttempt(workDir, state.AttemptID)
			}
		}
	}
}

// evaluateRequiredGates resolves graph-authored execution documents that are
// required and linked to any of the governing artifact IDs, then runs each
// one. When a gate declares a ratchet threshold, the command's numeric output
// is compared against the threshold after a successful exit; a ratchet miss
// demotes the gate status to "fail" and records the evidence the orchestrator
// surfaces as part of its landing decision.

func preDispatchCheckpointDirtyPaths(projectRoot string) ([]string, error) {
	out, err := internalgit.Command(context.Background(), projectRoot,
		"status", "--porcelain=v1", "-z", "--untracked-files=all", "--ignored=matching", "--", ".").CombinedOutput()
	if err != nil {
		return nil, fmt.Errorf("listing checkpoint dirt: %s: %w", strings.TrimSpace(string(out)), err)
	}
	if len(out) == 0 {
		return nil, nil
	}

	seen := make(map[string]bool)
	paths := make([]string, 0, 8)
	for len(out) > 0 {
		recordEnd := bytes.IndexByte(out, 0)
		if recordEnd == -1 {
			recordEnd = len(out)
		}
		record := out[:recordEnd]
		if recordEnd < len(out) {
			out = out[recordEnd+1:]
		} else {
			out = nil
		}
		if len(record) < 3 {
			continue
		}
		status := string(record[:2])
		path := filepath.ToSlash(string(record[3:]))
		if status == "!!" && !preDispatchCheckpointAllowedPath(path) {
			continue
		}
		if preDispatchCheckpointIgnoredPath(path) {
			continue
		}
		if isMaterializedSkillSymlink(projectRoot, path) {
			continue
		}
		if path != "" && !seen[path] {
			seen[path] = true
			paths = append(paths, path)
		}
		if record[0] == 'R' || record[0] == 'C' {
			recordEnd = bytes.IndexByte(out, 0)
			if recordEnd == -1 {
				recordEnd = len(out)
			}
			record = out[:recordEnd]
			if recordEnd < len(out) {
				out = out[recordEnd+1:]
			} else {
				out = nil
			}
			path := filepath.ToSlash(string(record))
			if status == "!!" && !preDispatchCheckpointAllowedPath(path) {
				continue
			}
			if preDispatchCheckpointIgnoredPath(path) {
				continue
			}
			if isMaterializedSkillSymlink(projectRoot, path) {
				continue
			}
			if path != "" && !seen[path] {
				seen[path] = true
				paths = append(paths, path)
			}
		}
	}
	return paths, nil
}

func preDispatchCheckpointAllowedPath(path string) bool {
	switch {
	case path == ".ddx/beads.jsonl":
		return true
	case path == ".ddx/beads-archive.jsonl":
		return true
	case strings.HasPrefix(path, ".ddx/executions/"):
		return true
	case strings.HasPrefix(path, ".ddx/metrics/"):
		return true
	case strings.HasPrefix(path, ".ddx/runs/"):
		return true
	case path == ExecutionCleanupMetadataFileName:
		return true
	default:
		return false
	}
}

func preDispatchCheckpointIgnoredPath(path string) bool {
	switch {
	case path == ".ddx/.git-tracker.lock":
		return true
	case strings.HasPrefix(path, ".ddx/.git-tracker.lock/"):
		return true
	case path == ".ddx/beads.lock":
		return true
	case strings.HasPrefix(path, ".ddx/beads.lock/"):
		return true
	case strings.HasPrefix(path, ".ddx/attachments/"):
		return true
	case path == ".ddx/run-state.json":
		return true
	case path == ".ddx/run-state":
		return true
	case strings.HasPrefix(path, ".ddx/run-state/"):
		return true
	case preDispatchCheckpointIgnoredExecutionEmbeddedPath(path):
		return true
	case strings.HasPrefix(path, ".ddx/beads.jsonl.tmp-"):
		return true
	case path == ".ddx/workers":
		return true
	case strings.HasPrefix(path, ".ddx/workers/"):
		return true
	default:
		return false
	}
}

func preDispatchCheckpointIgnoredExecutionEmbeddedPath(path string) bool {
	const prefix = ".ddx/executions/"
	if !strings.HasPrefix(path, prefix) {
		return false
	}
	rest := strings.TrimPrefix(path, prefix)
	attemptID, remainder, ok := strings.Cut(rest, "/")
	if !ok || attemptID == "" {
		return false
	}
	return remainder == "embedded" || strings.HasPrefix(remainder, "embedded/")
}

