			Output:   `{"classification":"transport","recommended_action":"release_claim_retry","rationale":"transient","suggested_amendments":[],"suggested_followup_beads":[]}`,
		}, nil
	default:
		r.t.Fatalf("unexpected prompt source: %q", opts.PromptSource)
		return nil, nil
	}
}

