type doctorUnjamSummary struct {
	ProjectRoot       string                 `json:"project_root"`
	Actions           []doctorUnjamAction    `json:"actions,omitempty"`
	ReportOnly        []doctorUnjamPathIssue `json:"report_only,omitempty"`
	StaleClaims       []string               `json:"stale_claims,omitempty"`
	TrackerRepaired   bool                   `json:"tracker_repaired,omitempty"`
	TrackerRepairFind int                    `json:"tracker_repair_findings,omitempty"`
}

type doctorUnjamAction struct {
	Kind    string   `json:"kind"`
	Paths   []string `json:"paths,omitempty"`
	Ref     string   `json:"ref,omitempty"`
	Message string   `json:"message,omitempty"`
}

type doctorUnjamPathIssue struct {
	Path   string `json:"path"`
	Reason string `json:"reason"`
	Status string `json:"status,omitempty"`
}

type doctorDirtyEntry struct {
	Status string
	Path   string
}

func (f *CommandFactory) runDoctorUnjam(cmd *cobra.Command) error {
	projectRoot := resolveProjectRoot("", f.WorkingDir)
	if projectRoot == "" {
		projectRoot = f.WorkingDir
	}

	summary := doctorUnjamSummary{ProjectRoot: projectRoot}
	if projectRoot == "" {
		return fmt.Errorf("doctor --unjam: project root is empty")
	}

	if err := agent.WithMainGitLock(projectRoot, "doctor_unjam", func() error {
		if err := repairTrackerPhantomDeps(projectRoot, &summary); err != nil {
			return err
		}

		dirtyEntries, err := collectDoctorDirtyEntries(projectRoot)
		if err != nil {
			return err
		}
		if len(dirtyEntries) == 0 {
			return nil
		}

		ddxOwned, reportOnly := splitDoctorUnjamPaths(projectRoot, dirtyEntries)
		if len(reportOnly) > 0 {
			summary.ReportOnly = append(summary.ReportOnly, reportOnly...)
		}

		if len(ddxOwned) > 0 {
			if err := checkpointDoctorUnjamPaths(projectRoot, ddxOwned); err != nil {
				return err
			}
			summary.Actions = append(summary.Actions, doctorUnjamAction{
				Kind:  "checkpoint",
				Paths: append([]string(nil), ddxOwned...),
			})
		}

		preserveGroups, preserveReports, err := groupDoctorPreservePaths(projectRoot, dirtyEntries, ddxOwned)
		if err != nil {
			return err
		}
		if len(preserveReports) > 0 {
			summary.ReportOnly = append(summary.ReportOnly, preserveReports...)
		}
		for ref, paths := range preserveGroups {
			if err := stashDoctorPreservePaths(projectRoot, ref, paths); err != nil {
				return err
			}
			summary.Actions = append(summary.Actions, doctorUnjamAction{
				Kind:    "stash",
				Paths:   append([]string(nil), paths...),
				Ref:     ref,
				Message: "ddx doctor --unjam preserve " + ref,
			})
		}

		removedOrphans, err := pruneDoctorUnjamWorktrees(projectRoot)
		if err != nil {
			return err
		}
		if len(removedOrphans) > 0 {
			summary.Actions = append(summary.Actions, doctorUnjamAction{
				Kind:  "remove-orphan-worktree",
				Paths: append([]string(nil), removedOrphans...),
			})
		}

		pruned, err := pruneDoctorWorktreeRegistry(projectRoot)
		if err != nil {
			return err
		}
		if pruned {
			summary.Actions = append(summary.Actions, doctorUnjamAction{
				Kind: "worktree-prune",
			})
		}

		staleClaims, err := releaseDoctorStaleClaims(projectRoot)
		if err != nil {
			return err
		}
		if len(staleClaims) > 0 {
			summary.StaleClaims = append(summary.StaleClaims, staleClaims...)
			summary.Actions = append(summary.Actions, doctorUnjamAction{
				Kind:  "release-claim",
				Paths: append([]string(nil), staleClaims...),
			})
		}

		return nil
	}); err != nil {
		return err
	}

	enc := json.NewEncoder(cmd.OutOrStdout())
	enc.SetIndent("", "  ")
	return enc.Encode(summary)
}

func repairTrackerPhantomDeps(projectRoot string, summary *doctorUnjamSummary) error {
	path := ddxroot.JoinProject(projectRoot, "beads.jsonl")
	if _, err := os.Stat(path); err != nil {
		if os.IsNotExist(err) {
			return nil
		}
		return err
	}
	report, err := bead.BeadDoctorFix(path, time.Now)
	if err != nil {
		return err
	}
	if !report.Clean() {
		summary.TrackerRepaired = true
		summary.TrackerRepairFind = len(report.Findings)
	}
	return nil
}

